// Combine LinkedIn URLs and work emails into a single inputs array
const linkedinRaw = $input.first().json.linkedinProfiles || '';
const emailsRaw = $input.first().json.workEmails || '';

const linkedin = linkedinRaw
  .split(',')
  .map(s => s.trim())
  .filter(s => s.length > 0);

const emails = emailsRaw
  .split(',')
  .map(s => s.trim())
  .filter(s => s.length > 0);

const inputs = [...linkedin, ...emails];

return [{
  json: {
    inputs,
    slackChannel: $input.first().json.slackChannel
  }
}];

// Parse CSV response from ScraperCity and return one item per contact
const raw = $input.first().json.data || $input.first().json.body || '';

if (!raw || typeof raw !== 'string') {
  // Attempt to handle if result is already an array/object
  const direct = $input.first().json;
  if (Array.isArray(direct)) {
    return direct.map(row => ({ json: row }));
  }
  return [{ json: { error: 'No parsable data returned', raw: JSON.stringify(direct) } }];
}

// Split into lines and parse header + rows
const lines = raw.split('\n').filter(l => l.trim().length > 0);
if (lines.length < 2) {
  return [{ json: { error: 'CSV has no data rows', raw } }];
}

const headers = lines[0].split(',').map(h => h.trim().replace(/^"|"$/g, ''));
const results = [];

for (let i = 1; i < lines.length; i++) {
  const cols = lines[i].split(',').map(c => c.trim().replace(/^"|"$/g, ''));
  const record = {};
  headers.forEach((h, idx) => {
    record[h] = cols[idx] || '';
  });
  // Only include records that have some phone data
  const phoneKey = headers.find(h => /phone|mobile/i.test(h));
  if (phoneKey && record[phoneKey]) {
    results.push({ json: record });
  } else if (!phoneKey) {
    // No phone column detected -- pass through anyway
    results.push({ json: record });
  }
}

return results.length > 0 ? results : [{ json: { info: 'No phone numbers found in results' } }];

// Build a Slack-friendly message block for each contact with a mobile number
const items = $input.all();

const lines = items.map((item, idx) => {
  const d = item.json;
  const name = d.full_name || d.name || d.first_name && d.last_name
    ? `${d.first_name || ''} ${d.last_name || ''}`.trim()
    : 'Unknown';
  const phone = d.mobile_phone || d.phone || d.mobile || 'N/A';
  const linkedin = d.linkedin_url || d.linkedin || d.input || 'N/A';
  const email = d.email || 'N/A';
  return `${idx + 1}. *${name}* -- Phone: ${phone} -- Email: ${email} -- LinkedIn: ${linkedin}`;
});

const summary = `*Mobile Finder Results* -- ${items.length} contact(s) found with phone numbers:\n\n${lines.join('\n')}`;

return [{
  json: {
    slackMessage: summary,
    contactCount: items.length,
    slackChannel: $('Store Run ID').item.json.slackChannel
  }
}];
